/**
 * Share-card PNG generator. Paints a polished 1080x1080 canvas with the
 * puzzle's revealed picture, the player's time, mistakes, and a tiny
 * "bilko.run/etch" wordmark. Returned as a data: URL so it can be copied to
 * the clipboard OR downloaded.
 *
 * The whole thing is ~3 KB of code; no image assets, no fonts loaded.
 */
import type { Board, EtchMode, EtchSize } from '../../engine';

interface CardSpec {
  board: Board;
  size: EtchSize;
  mode: EtchMode;
  timeMs: number;
  mistakes: number;
  hintsUsed: number;
  perfect: boolean;
  isPersonalBest: boolean;
}

const W = 1080;
const H = 1080;

function fmt(ms: number): string {
  const total = Math.floor(ms / 1000);
  const m = Math.floor(total / 60), s = total % 60;
  return `${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`;
}

function readTokens() {
  const cs = getComputedStyle(document.documentElement);
  return {
    paper: cs.getPropertyValue('--paper').trim() || '#ffffff',
    ink: cs.getPropertyValue('--ink').trim() || '#1c1c1e',
    accent: cs.getPropertyValue('--entered').trim() || '#3b82f6',
  };
}

/** Render the share card and return a data: URL PNG. */
export async function renderShareCard(spec: CardSpec): Promise<string> {
  const canvas = document.createElement('canvas');
  canvas.width = W; canvas.height = H;
  const ctx = canvas.getContext('2d');
  if (!ctx) throw new Error('canvas 2d unavailable');

  const { paper, ink, accent } = readTokens();

  // Background
  ctx.fillStyle = paper;
  ctx.fillRect(0, 0, W, H);

  // Top stripe (brand)
  ctx.fillStyle = ink;
  ctx.fillRect(0, 0, W, 6);

  // Hero — the puzzle picture
  const padding = 100;
  const heroSize = W - padding * 2;
  const cells = Math.max(spec.board.rows, spec.board.cols);
  const cellPx = Math.floor(heroSize / cells);
  const drawW = cellPx * spec.board.cols;
  const drawH = cellPx * spec.board.rows;
  const heroX = (W - drawW) / 2;
  const heroY = 160;

  // Soft frame around the picture
  ctx.fillStyle = ink;
  ctx.fillRect(heroX - 8, heroY - 8, drawW + 16, drawH + 16);
  ctx.fillStyle = paper;
  ctx.fillRect(heroX, heroY, drawW, drawH);

  ctx.fillStyle = ink;
  for (let r = 0; r < spec.board.rows; r++) {
    for (let col = 0; col < spec.board.cols; col++) {
      if (spec.board.solution[r * spec.board.cols + col] === 1) {
        ctx.fillRect(heroX + col * cellPx, heroY + r * cellPx, cellPx, cellPx);
      }
    }
  }

  // Title row
  ctx.fillStyle = ink;
  ctx.font = '700 36px system-ui, -apple-system, sans-serif';
  ctx.textBaseline = 'top';
  ctx.textAlign = 'left';
  ctx.fillText('Bilko · Etch', 80, 64);

  // Mode + size pill
  ctx.font = '500 22px system-ui, sans-serif';
  ctx.fillStyle = ink + 'aa';
  ctx.textAlign = 'right';
  const modeText = `${spec.mode === 'daily' ? 'Daily' : 'Free'} · ${spec.size}`;
  ctx.fillText(modeText, W - 80, 72);

  // Stats row beneath the hero
  const statsY = heroY + drawH + 80;
  const cellW = (W - padding * 2) / 3;
  ctx.textAlign = 'center';
  ctx.textBaseline = 'top';

  const stats: Array<{ label: string; value: string }> = [
    { label: 'Time', value: fmt(spec.timeMs) },
    { label: 'Mistakes', value: String(spec.mistakes) },
    { label: 'Hints', value: String(spec.hintsUsed) },
  ];

  stats.forEach((stat, i) => {
    const x = padding + cellW * i + cellW / 2;
    ctx.fillStyle = ink + '80';
    ctx.font = '500 22px system-ui, sans-serif';
    ctx.fillText(stat.label.toUpperCase(), x, statsY);
    ctx.fillStyle = ink;
    ctx.font = '700 72px system-ui, sans-serif';
    ctx.fillText(stat.value, x, statsY + 36);
  });

  // Badge area
  const badgeY = statsY + 170;
  if (spec.perfect) {
    ctx.fillStyle = accent;
    ctx.font = '700 28px system-ui, sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText('◆  PERFECT SOLVE  ◆', W / 2, badgeY);
  } else if (spec.isPersonalBest) {
    ctx.fillStyle = accent;
    ctx.font = '700 28px system-ui, sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText('★  PERSONAL BEST  ★', W / 2, badgeY);
  }

  // Footer wordmark
  ctx.fillStyle = ink + '99';
  ctx.font = '500 24px system-ui, sans-serif';
  ctx.textAlign = 'center';
  ctx.fillText('bilko.run/etch', W / 2, H - 80);

  return canvas.toDataURL('image/png');
}

/** Copy the rendered share card to clipboard as a PNG blob. */
export async function copyShareCard(spec: CardSpec): Promise<boolean> {
  try {
    const url = await renderShareCard(spec);
    const blob = await (await fetch(url)).blob();
    // ClipboardItem availability is gated to secure contexts + modern browsers.
    const Item = (window as unknown as { ClipboardItem?: typeof ClipboardItem }).ClipboardItem;
    if (Item && navigator.clipboard && 'write' in navigator.clipboard) {
      await navigator.clipboard.write([new Item({ 'image/png': blob })]);
      return true;
    }
  } catch { /* fall through */ }
  return false;
}

/** Trigger a download of the share-card data URL. */
export function downloadShareCard(dataUrl: string, filename = 'etch-share.png'): void {
  const a = document.createElement('a');
  a.href = dataUrl;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  a.remove();
}
